class Solution {
public:
    int longestCommonSubsequence(string text1, string text2) {
        int m = text1.size(), n = text2.size();
        vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));
        for (int i = 1; i <= m; ++i) {
            for (int j = 1; j <= n; ++j) {
                if (text1[i - 1] == text2[j - 1]) {
                    dp[i][j] = dp[i - 1][j - 1] + 1;
                } else {
                    dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
                }
            }
        }
        return dp[m][n];
    }
};
efficiency: HIGH
time complexity: O(m*n)
space complexity: O(m*n)
energy implications: LOW
explanation: Dynamic programming approach is used to build a 2D table where dp[i][j] represents the length of the longest common subsequence of text1[0..i-1] and text2[0..j-1]. The final result is stored in dp[m][n].
